procedure decode_byte
  (
   ctx        : in out t_slip;
   input      : in     Unsigned_8;
   data       :    out t_decode_result;
   frame_done :    out Boolean
  )

procedure decode_frame
  (
   frame    : in     t_buffer;
   data     : in out t_buffer;
   end_at   :    out Natural;
   cursor   :    out Natural;
   has_data :    out Boolean
  )

procedure encode_byte
  (
   byte   : in     Unsigned_8;
   frame  : in out t_buffer;
